refsection.programlisting:

load(GROCERDIR+'\data\juselius.dat')
// create dummies used for regression p.111-112
post83q1=dummy(['1973q1';'2003q1'],['1983q1';'2003q1']);
dum75q4=dummy(['1973q1';'2003q1'],'1975q4')-0.5*dummy(['1973q1';'2003q1'],['1976q1';'1976q2']);
dum76q4=dummy(['1973q1';'2003q1'],'1976q4');
dum83q2=dummy(['1973q1';'2003q1'],'1983q2');
dum83q1=dummy(['1973q1';'2003q1'],'1983q1');

rj1=johansen(1,'dnk_Lm3rC','dnk_Lyr','dnk_DLpy','dnk_Rm','dnk_Rb','exo_lt=trend^1;post(1983q1)','exo_st=const;dum75q4;dum76q4;dum83q1')
// Example taken from function johansen_d(). The number of lags in the VAR is set to 1.
// The endogenous variables are 'dnk_Lm3rC','dnk_Lyr','dnk_DLpy','dnk_Rm','dnk_Rb'.
// There are 2 exogenous variables in the cointegration space: a trend and a dummy (post(1983q1).
// There are 4 exogenous variables in the short run dynamic: a constant and 3 dummies.

load(GROCERDIR+'/data/datajpl.dat')
[result] = johansen(9,'illinos','indiana','kentucky','michigan','ohio','pennsyvlania','tennesse', 'westvirginia','stat_meth=asym','exo_st=const')
// Example with asymptotic critical tables, allowing to recover James Le Sage (http://www.spatial-econometrics.com/html/mbook.pdf) example.
